// tests/daemon_protocol_e2e.rs

#[tokio::test]
async fn test_protocol_version_mismatch() {
    let daemon = DaemonProcess::spawn().await.unwrap();

    // Connect directly to socket and send wrong version
    let mut stream = UnixStream::connect(&daemon.socket_path).await.unwrap();

    let bad_envelope = Envelope {
        version: 99,  // Wrong version
        id: 1,
        payload: rmp_serde::to_vec(&Request::Health).unwrap(),
    };

    let bytes = rmp_serde::to_vec(&bad_envelope).unwrap();
    stream.write_u32(bytes.len() as u32).await.unwrap();
    stream.write_all(&bytes).await.unwrap();

    // Read response
    let len = stream.read_u32().await.unwrap();
    let mut buf = vec![0u8; len as usize];
    stream.read_exact(&mut buf).await.unwrap();

    let response: Envelope = rmp_serde::from_slice(&buf).unwrap();
    let error: Response = rmp_serde::from_slice(&response.payload).unwrap();

    match error {
        Response::Error { code, message } => {
            assert_eq!(code, error_codes::VERSION_MISMATCH);
            tracing::info!(code, message = message.as_str(), "Version mismatch error");
        }
        _ => panic!("Expected Error response"),
    }
}

#[tokio::test]
async fn test_unknown_model_error() {
    let daemon = DaemonProcess::spawn().await.unwrap();
    let client = DaemonClient::with_socket_path(daemon.socket_path.clone());

    let result = client.embed(&["test"], "nonexistent-model-xyz", None).await;

    assert!(result.is_err());
    let err = result.unwrap_err();
    tracing::info!(error = %err, "Unknown model error");
    assert!(err.to_string().contains("MODEL_LOAD_FAILED") || 
            err.to_string().contains("not found"));
}

#[tokio::test]
async fn test_oversized_request_rejection() {
    let daemon = DaemonProcess::spawn().await.unwrap();

    // Connect directly and send oversized request
    let mut stream = UnixStream::connect(&daemon.socket_path).await.unwrap();

    // Claim we're sending 20MB (should be rejected)
    stream.write_u32(20 * 1024 * 1024).await.unwrap();

    // Connection should be closed
    let mut buf = [0u8; 1];
    let result = stream.read(&mut buf).await;

    // Either error or 0 bytes (closed)
    assert!(result.is_err() || result.unwrap() == 0);
    tracing::info!("Oversized request rejected");
}

#[tokio::test]
async fn test_all_error_codes_e2e() {
    let daemon = DaemonProcess::spawn().await.unwrap();
    let client = DaemonClient::with_socket_path(daemon.socket_path.clone());

    // Test each error condition
    let error_tests = vec![
        ("UNKNOWN_MODEL", client.embed(&["x"], "fake-model", None).await),
        ("invalid reranker", client.rerank("q", &["d"], "fake-reranker").await),
    ];

    for (name, result) in error_tests {
        assert!(result.is_err(), "{name} should fail");
        tracing::info!(test = name, error = %result.unwrap_err(), "Error test passed");
    }
}
