            background: default_color,
            highlight: default_color,
            username: default_color,
            hashtag: default_color,
            mention: default_color,
            link: default_color,
            timestamp: default_color,
            score_high: default_color,
            score_medium: default_color,
            score_low: default_color,
            color_support: ColorSupport::None,
            high_contrast: false,
        }
    }

    /// List available built-in themes
    pub fn available_themes() -> &'static [&'static str] {
        &["dark", "dark-256", "light", "minimal", "high-contrast", "no-color"]
    }

    /// Get theme by name
    pub fn by_name(name: &str) -> Option<Self> {
        match name.to_lowercase().as_str() {
            "dark" => Some(Self::dark()),
            "dark-256" | "dark256" => Some(Self::dark_256()),
            "light" => Some(Self::light()),
            "minimal" | "basic" => Some(Self::minimal()),
            "high-contrast" | "highcontrast" | "hc" => Some(Self::high_contrast()),
            "no-color" | "nocolor" | "none" => Some(Self::no_color()),
            _ => None,
        }
    }

    /// Auto-detect best theme for terminal
    pub fn detect_color_support() -> ColorSupport {
        ColorSupport::detect()
    }

    /// Get theme appropriate for detected color support
    pub fn for_color_support(support: ColorSupport) -> Self {
        match support {
            ColorSupport::TrueColor => Self::dark(),
            ColorSupport::Extended => Self::dark_256(),
            ColorSupport::Basic => Self::minimal(),
            ColorSupport::None => Self::no_color(),
        }
    }

    /// Get style for a score value (0.0 - 1.0)
    pub fn score_style(&self, score: f32) -> Style {
        let color = if score >= 0.8 {
            self.score_high
        } else if score >= 0.5 {
            self.score_medium
        } else {
            self.score_low
        };
        Style::new().foreground(color).bold()
    }

    /// Get heading style
    pub fn heading_style(&self) -> Style {
        Style::new().foreground(self.heading).bold()
    }

    /// Get error style
    pub fn error_style(&self) -> Style {
        Style::new().foreground(self.error).bold()
    }

    /// Get warning style
    pub fn warning_style(&self) -> Style {
        Style::new().foreground(self.warning)
    }

    /// Get success style
    pub fn success_style(&self) -> Style {
        Style::new().foreground(self.success)
    }

    /// Get muted style
    pub fn muted_style(&self) -> Style {
        Style::new().foreground(self.muted)
    }
}
