#!/bin/bash
set -euo pipefail
LOG="tests/e2e/results/service_$(date +%Y%m%d_%H%M%S).log"
log() { echo "[$(date +%H:%M:%S)] $*" | tee -a "$LOG"; }
PASS=0; FAIL=0

# Detect platform
if [[ "$(uname)" == "Darwin" ]]; then
    PLATFORM="launchd"
else
    PLATFORM="systemd"
fi
log "Platform: $PLATFORM"

if [ "$PLATFORM" = "systemd" ]; then
    # Test systemd installation
    log "TEST: Install systemd service"
    bash scripts/daemon/install-systemd.sh 2>&1 | tee -a "$LOG"
    [ $? -eq 0 ] && ((PASS++)) || ((FAIL++))

    log "TEST: Start service"
    systemctl --user start xf-daemon
    sleep 2
    systemctl --user is-active xf-daemon && { log "  PASS: active"; ((PASS++)); } || { log "  FAIL: not active"; ((FAIL++)); }

    log "TEST: Health check"
    xf daemon status && { log "  PASS"; ((PASS++)); } || { log "  FAIL"; ((FAIL++)); }

    log "TEST: Socket exists"
    SOCK="${XF_DAEMON_SOCKET:-/tmp/xf-daemon.sock}"
    [ -S "$SOCK" ] && { log "  PASS: $SOCK exists"; ((PASS++)); } || { log "  FAIL: no socket"; ((FAIL++)); }

    log "TEST: Search via daemon"
    xf search "test" --semantic --daemon --json >/dev/null 2>&1 && \
        { log "  PASS"; ((PASS++)); } || { log "  FAIL"; ((FAIL++)); }

    log "TEST: Stop service"
    systemctl --user stop xf-daemon
    sleep 1
    ! systemctl --user is-active xf-daemon && { log "  PASS: stopped"; ((PASS++)); } || { log "  FAIL: still running"; ((FAIL++)); }

    log "TEST: Socket cleaned up"
    [ ! -S "$SOCK" ] && { log "  PASS"; ((PASS++)); } || { log "  FAIL: socket still exists"; ((FAIL++)); }

    # Cleanup
    systemctl --user disable xf-daemon 2>/dev/null || true
else
    # Test launchd installation
    log "TEST: Install launchd agent"
    bash scripts/daemon/install-launchd.sh 2>&1 | tee -a "$LOG"
    [ $? -eq 0 ] && ((PASS++)) || ((FAIL++))

    log "TEST: Agent loaded"
    sleep 2
    launchctl print "gui/$(id -u)/com.dicklesworthstone.xf-daemon" >/dev/null 2>&1 && \
        { log "  PASS"; ((PASS++)); } || { log "  FAIL"; ((FAIL++)); }

    log "TEST: Health check"
    xf daemon status && { log "  PASS"; ((PASS++)); } || { log "  FAIL"; ((FAIL++)); }

    # Cleanup
    launchctl bootout "gui/$(id -u)/com.dicklesworthstone.xf-daemon" 2>/dev/null || true
fi

log "========================="
log "Results: $PASS passed, $FAIL failed"
exit $FAIL
```

